# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

import requests, json
from PIL import Image
from io import BytesIO


def get_image(url):
    response = requests.get(url)
    img = Image.open(BytesIO(response.content))
    return img


def annotate(img):
    # Get the image url from the user
    url = input('Enter image URL: ')

    # Download and open the image
    img = get_image(url)

    # Display the image in a window
    img.show()

    # Ask for the label of the image
    label = input('Enter label: ')

    # Return the image, label pair as a tuple
    return (img, label)


def majority_vote(votes):
    votes = dict(votes)
    max_label = None
    max_count = 0
    for label in votes:
        if votes[label] > max_count:
            max_label = label
            max_count = votes[label]

    return max_label


def main():
    # Initialize the list of image, labels pairs
    imgs = []

    # Ask user to annotate 5 images.
    for i in range(0, 5):
        img, label = annotate()

        # Append the image and its label pair to the list
        imgs.append((img, label))

    # Initialize a dictionary to count votes of each label
    votes = dict()

    # Iterate through all the pairs in the list
    for img, label in imgs:
        # If this is first time we see this label then initialize it with 1 vote else increment its vote by one.
        if not label in votes:
            votes[label] = 1

        # Increment the vote of this label by one.
        votes[label] += 1

    # Get majority vote
    max_label = majority_vote(votes)

    print('The most voted label is', max_label)


if __name__ == '__main__':
    main()